mapper.select:
SELECT * FROM company_employee
WHERE company_id = #{companyId}
ORDER BY create_time DESC
    LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE company_employee
name = #{name}, id_card = #{idCard}, job_position = #{jobPosition}, entry_date = #{entryDate}, is_active = #{isActive}, update_time = #{updateTime},
WHERE id = #{id}
